args.sqlite_command:
DROP TABLE IF EXISTS J09A_temp;
CREATE TABLE J09A_temp AS
SELECT d.*
FROM decision_table d
WHERE d.TOUR LIKE 'J09A%';
ALTER TABLE J09A_temp ADD COLUMN ENTSCHEIDUNG TEXT;

UPDATE J09A_temp
SET ENTSCHEIDUNG = CASE
  WHEN (
    SELECT COUNT(DISTINCT t2.EQUNR)
    FROM J09A_temp t2
    WHERE t2.HAUS = J09A_temp.HAUS
  ) < 3 THEN 'KSA'
  ELSE 'EVU'
END;

UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 = 0;
UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 500 AND 599;
UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE HOUSE_NUM1 BETWEEN 900 AND 999;
UPDATE J09A_temp SET ENTSCHEIDUNG = 'EVU' WHERE CITY2 IN ('Wiblingwerde', 'Breckerfeld');

ALTER TABLE J09A_temp ADD COLUMN "Meter Reading (MR) Doc. No." TEXT;
ALTER TABLE J09A_temp ADD COLUMN TITLE TEXT;
ALTER TABLE J09A_temp ADD COLUMN FORENAME TEXT;
ALTER TABLE J09A_temp ADD COLUMN SURNAME TEXT;
ALTER TABLE J09A_temp ADD COLUMN STREET TEXT;
ALTER TABLE J09A_temp ADD COLUMN STREETNO TEXT;
ALTER TABLE J09A_temp ADD COLUMN EMAIL TEXT;

UPDATE J09A_temp
SET "Meter Reading (MR) Doc. No." = (
  SELECT eablg."Meter Reading (MR) Doc. No."
  FROM eablg
  WHERE eablg.Installation = J09A_temp.ANLAGE
  LIMIT 1
);

UPDATE J09A_temp
SET TITLE = COALESCE((SELECT s.TITLE FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.TITLE FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1)),
    FORENAME = COALESCE((SELECT s.FORENAME FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.FORENAME FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1)),
    SURNAME = COALESCE((SELECT s.SURNAME FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.SURNAME FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1)),
    STREET = COALESCE((SELECT s.STREET FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.STREET FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1)),
    STREETNO = COALESCE((SELECT s.STREETNO FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.STREETNO FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1)),
    POST_CODE1 = COALESCE((SELECT s.POST_CODE1 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.POST_CODE1 FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1), POST_CODE1),
    CITY1 = COALESCE((SELECT s.CITY1 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.CITY1 FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1), CITY1),
    CITY2 = COALESCE((SELECT s.CITY2 FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.CITY2 FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1), CITY2),
    EMAIL = COALESCE((SELECT s.EMAIL FROM sales_master s WHERE s.EQUNR = J09A_temp.EQUNR LIMIT 1), (SELECT n.EMAIL FROM net_master n WHERE n.EQUNR = J09A_temp.EQUNR LIMIT 1));

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'MANDATORY_READING'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Maschinelle Schätzung - SAP'
    AND substr("Record created on", 1, 4) IN ('2023', '2024')
  GROUP BY EQUNR
  HAVING COUNT(DISTINCT substr("Record created on", 1, 4)) = 2
);

UPDATE J09A_temp
SET ENTSCHEIDUNG = 'DIRECT_MAIL'
WHERE EQUNR IN (
  SELECT EQUNR
  FROM eabl
  WHERE ISTABLART_TXT = 'Ablesung durch Kunden - SAP'
    AND substr("Record created on", 1, 4) IN ('2023', '2024')
  GROUP BY EQUNR
  HAVING COUNT(DISTINCT substr("Record created on", 1, 4)) = 2
);
